func (gs *GameServer) getUserRoleFromHeaders(headers map[string]string) UserRole {
	roleStr, exists := headers["role"]
	if !exists {
		return RolePlayer
	}
	
	switch strings.ToLower(roleStr) {
	case "admin":
		return RoleAdmin
	case "moderator":
		return RoleModerator
	case "owner":
		return RoleOwner
	default:
		return RolePlayer
	}
}

func (gs *GameServer) handleConnection(conn net.Conn) {
	defer conn.Close()
	
	// Read headers from connection
	headers := make(map[string]string)
	scanner := bufio.NewScanner(conn)
	
	for scanner.Scan() {
		line := scanner.Text()
		if line == "" {
			break
		}
		
		parts := strings.SplitN(line, ":", 2)
		if len(parts) == 2 {
			headers[strings.TrimSpace(parts[0])] = strings.TrimSpace(parts[1])
		}
	}
	
	// Get user role from headers
	role := gs.getUserRoleFromHeaders(headers)
	
	// Get user ID from headers or generate one
	userID, exists := headers["user_id"]
	if !exists {
		userID = fmt.Sprintf("user_%d", time.Now().Unix())
	}
	
	userName, exists := headers["username"]
	if !exists {
		userName = "Anonymous"
	}
	
	user := &User{
		ID:       userID,
		Name:     userName,
		Role:     role,
		Conn:     conn,
		LastSeen: time.Now(),
	}
	
	gs.usersMu.Lock()
	gs.users[userID] = user
	gs.usersMu.Unlock()
	
	conn.Write([]byte(fmt.Sprintf("Welcome %s (role: %s)\n", userName, role.String())))
	
	// Handle chat messages
	for scanner.Scan() {
		message := scanner.Text()
		if strings.HasPrefix(message, "/") {
			gs.processCommand(user, message)
		} else {
			gs.broadcastMessage(user, message)
		}
	}
}

func (gs *GameServer) processCommand(user *User, message string) {
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return
	}
	
	commandName := parts[0]
	cmd, exists := gs.commands[commandName]
	if !exists {
		user.Conn.Write([]byte(fmt.Sprintf("Unknown command: %s\n", commandName)))
		return
	}
	
	if cmd.MinRole > user.Role {
		user.Conn.Write([]byte("Insufficient permissions\n"))
		return
	}
	
	args := parts[1:]
	cmd.Handler(user, args, gs)
}

func (gs *GameServer) broadcastMessage(user *User, message string) {
	gs.usersMu.RLock()
	defer gs.usersMu.RUnlock()
	
	for _, u := range gs.users {
		if u != user {
			u.Conn.Write([]byte(fmt.Sprintf("[%s]: %s\n", user.Name, message)))
		}
	}
}

